/* Evidence: cmem-const-volatile-limits-1lie3t */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 2269; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct lifetime_handle { int value; unsigned generation; int live; };

static int evidence_cmem_const_volatile_limits_1lie3t(const struct lifetime_handle *item, unsigned expected) {
  if (item == NULL || !item->live) return -1;
  if (item->generation != expected) return -2;
  return item->value;
}

int main(void) {
  struct lifetime_handle item = { 12, 4u, 1 };
  int stale = evidence_cmem_const_volatile_limits_1lie3t(&item, 5u);
  int live = evidence_cmem_const_volatile_limits_1lie3t(&item, 4u);
  int invariant = stale == -2 && live == 12;
  printf("lifetime stale=%d live=%d invariant=%d\n", stale, live, invariant);
  return invariant ? 0 : 1;
}
